"use client";

import { useEffect, useRef, useState } from "react";

const BACKEND_URL =
  process.env.NEXT_PUBLIC_VOICE_BACKEND_URL || "http://localhost:8001";

type Message = {
  from: "user" | "assistant";
  text: string;
};

type Domain = "restaurant" | "ecommerce" | "car_booking";

const VOICES = [
  { id: "priya",  label: "Priya (Female)" },
  { id: "shruti", label: "Shruti (Female)" },
  { id: "Kavya",  label: "Kavya (Female)" },
  { id: "shubh",  label: "Shubh (Male)" },
  { id: "rohan",  label: "Rohan (Male)" },
];

export default function VoiceAssistant() {
  const [sessionId, setSessionId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [recording, setRecording] = useState(false);
  const [loading, setLoading] = useState(false);
  const [playing, setPlaying] = useState(false);
  const [domain, setDomain] = useState<Domain>("restaurant");
  const [voice, setVoice] = useState("priya");

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<BlobPart[]>([]);
  const bottomRef = useRef<HTMLDivElement | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Session UUID stored in localStorage
  useEffect(() => {
    if (typeof window === "undefined") return;
    let id = window.localStorage.getItem("aurora_voice_session");
    if (!id) {
      id = crypto.randomUUID();
      window.localStorage.setItem("aurora_voice_session", id);
    }
    setSessionId(id);
  }, []);

  // Auto-scroll to bottom when messages update
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const pushMsg = (msg: Message) =>
    setMessages((prev) => [...prev, msg]);

  // Notify backend of voice change
  const changeVoice = async (newVoice: string) => {
    setVoice(newVoice);
    try {
      await fetch(`${BACKEND_URL}/set-voice`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ voice: newVoice }),
      });
    } catch (err) {
      console.error("Failed to set voice:", err);
    }
  };

  // Play base64 audio returned from the backend
  const playAudio = (base64: string) => {
    try {
      const bytes = Uint8Array.from(atob(base64), (c) => c.charCodeAt(0));
      const blob = new Blob([bytes], { type: "audio/wav" });
      const url = URL.createObjectURL(blob);

      if (audioRef.current) {
        audioRef.current.pause();
        URL.revokeObjectURL(audioRef.current.src);
      }

      const audio = new Audio(url);
      audioRef.current = audio;
      setPlaying(true);

      audio.onended = () => {
        setPlaying(false);
        URL.revokeObjectURL(url);
      };
      audio.onerror = () => {
        setPlaying(false);
        URL.revokeObjectURL(url);
      };

      audio.play().catch((err) => {
        console.error("Audio play failed:", err);
        setPlaying(false);
      });
    } catch (err) {
      console.error("Audio decode failed:", err);
    }
  };

  // Call /query
  const sendTextToBackend = async (text: string) => {
    if (!sessionId) return;
    pushMsg({ from: "user", text });
    setLoading(true);

    try {
      const res = await fetch(`${BACKEND_URL}/query`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          text,
          user_id: sessionId,
          domain,
        }),
      });

      if (!res.ok) {
        throw new Error(await res.text());
      }

      const data: { response: string; audio_base64?: string } = await res.json();
      pushMsg({ from: "assistant", text: data.response });

      // Play TTS audio if returned
      if (data.audio_base64) {
        playAudio(data.audio_base64);
      }
    } catch (err) {
      console.error(err);
      pushMsg({
        from: "assistant",
        text: "Sorry, something went wrong talking to the voice backend.",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const trimmed = input.trim();
    if (!trimmed || loading) return;
    setInput("");
    await sendTextToBackend(trimmed);
  };

  // Mic recording helpers
  const startRecording = async () => {
    if (recording) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mr = new MediaRecorder(stream);
      audioChunksRef.current = [];

      mr.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mr.onstop = async () => {
        const blob = new Blob(audioChunksRef.current, { type: "audio/webm" });
        audioChunksRef.current = [];

        const formData = new FormData();
        formData.append("file", blob, "chunk.webm");

        setLoading(true);
        try {
          const res = await fetch(`${BACKEND_URL}/stt`, {
            method: "POST",
            body: formData,
          });
          if (!res.ok) {
            throw new Error(await res.text());
          }
          const data: { text: string } = await res.json();
          const transcript = (data.text || "").trim();
          if (transcript) {
            await sendTextToBackend(transcript);
          } else {
            pushMsg({
              from: "assistant",
              text: "I couldn't hear that clearly. Please try again.",
            });
            setLoading(false);
          }
        } catch (err) {
          console.error(err);
          pushMsg({
            from: "assistant",
            text: "Speech recognition failed. Please try again.",
          });
          setLoading(false);
        }

        stream.getTracks().forEach((t) => t.stop());
        setRecording(false);
      };

      mediaRecorderRef.current = mr;
      mr.start();
      setRecording(true);
      pushMsg({
        from: "assistant",
        text: "Listening… speak now.",
      });
    } catch (err) {
      console.error(err);
      pushMsg({
        from: "assistant",
        text: "Could not access microphone. Please check permissions.",
      });
    }
  };

  const stopRecording = () => {
    if (!recording || !mediaRecorderRef.current) return;
    mediaRecorderRef.current.stop();
  };

  return (
    <div className="surface rounded-2xl p-6 md:p-10 space-y-6 max-w-4xl mx-auto border border-gold/20 shadow-2xl relative overflow-hidden">
      {/* Subtle background glow */}
      <div className="absolute top-0 right-0 -mr-20 -mt-20 w-64 h-64 bg-gold/5 blur-[100px] pointer-events-none rounded-full" />

      {/* Header */}
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4 relative z-10">
        <div>
          <p className="section-label mb-2">Voice Assistant</p>
          <h2 className="font-serif text-2xl md:text-3xl font-light text-warm-white tracking-wide">
            Aurora Dining Concierge
          </h2>
        </div>
        <div className="flex items-center gap-4 flex-wrap">
          {/* Playing indicator */}
          {playing && (
            <span className="flex items-center gap-2 text-[11px] tracking-[0.12em] uppercase text-gold font-sans bg-gold/10 px-3 py-1.5 rounded-full border border-gold/20">
              <span className="inline-block w-2 h-2 rounded-full bg-gold animate-[pulse_1s_ease-in-out_infinite]" />
              Speaking
            </span>
          )}
          
          <div className="flex gap-4 bg-charcoal-light/50 p-2 rounded-lg border border-gold/10">
            {/* Voice selector */}
            <div className="flex items-center gap-2 text-xs font-sans">
              <label className="text-muted tracking-wide">Voice:</label>
              <select
                className="bg-transparent text-warm-white text-xs px-2 py-1 rounded cursor-pointer outline-none focus:ring-1 focus:ring-gold/50"
                value={voice}
                onChange={(e) => changeVoice(e.target.value)}
              >
                {VOICES.map((v) => (
                  <option key={v.id} value={v.id} className="bg-charcoal text-warm-white">
                    {v.label}
                  </option>
                ))}
              </select>
            </div>

            <div className="w-[1px] h-4 bg-gold/20 my-auto" />

            {/* Domain selector */}
            <div className="flex items-center gap-2 text-xs font-sans">
              <label className="text-muted tracking-wide">Domain:</label>
              <select
                className="bg-transparent text-warm-white text-xs px-2 py-1 rounded cursor-pointer outline-none focus:ring-1 focus:ring-gold/50"
                value={domain}
                onChange={(e) => setDomain(e.target.value as Domain)}
              >
                <option value="restaurant" className="bg-charcoal text-warm-white">Restaurant</option>
                <option value="ecommerce" className="bg-charcoal text-warm-white">E‑commerce</option>
                <option value="car_booking" className="bg-charcoal text-warm-white">Car booking</option>
              </select>
            </div>
          </div>
        </div>
      </div>

      {/* Chat window */}
      <div className="min-h-[400px] max-h-[50vh] overflow-y-auto space-y-4 border border-gold/10 rounded-xl p-5 bg-charcoal-deep/60 shadow-inner block scroll-smooth relative z-10 custom-scrollbar">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center space-y-3 opacity-60 mt-10">
            <div className="w-12 h-12 rounded-full border border-gold/30 flex items-center justify-center mb-2">
              <span className="text-gold text-lg">✦</span>
            </div>
            <p className="text-sm font-sans tracking-wide text-warm-white max-w-sm leading-relaxed">
              Start by speaking or typing a request, for example: "Book a table for 4 tomorrow dinner".
            </p>
          </div>
        )}
        
        {messages.map((m, idx) => (
          <div
            key={idx}
            className={`flex ${m.from === "user" ? "justify-end" : "justify-start"} animate-[fadeIn_0.3s_ease-out]`}
          >
            <div
              className={`px-5 py-3.5 text-sm md:text-[15px] font-sans leading-relaxed max-w-[85%] shadow-md ${
                m.from === "user"
                  ? "bg-gradient-to-br from-gold/20 to-gold/5 text-warm-white border border-gold/30 rounded-2xl rounded-tr-sm"
                  : "surface-light text-warm-white border border-white/10 rounded-2xl rounded-tl-sm"
              }`}
            >
              {m.text}
            </div>
          </div>
        ))}

        {loading && (
          <div className="flex justify-start animate-[fadeIn_0.3s_ease-out]">
            <div className="px-5 py-3.5 surface-light text-muted border border-white/5 rounded-2xl rounded-tl-sm text-sm font-sans flex items-center gap-2">
              <span className="flex gap-1">
                <span className="w-1.5 h-1.5 bg-gold/60 rounded-full animate-bounce" style={{ animationDelay: "0ms" }} />
                <span className="w-1.5 h-1.5 bg-gold/60 rounded-full animate-bounce" style={{ animationDelay: "150ms" }} />
                <span className="w-1.5 h-1.5 bg-gold/60 rounded-full animate-bounce" style={{ animationDelay: "300ms" }} />
              </span>
              <span className="ml-2 italic tracking-wide">Thinking...</span>
            </div>
          </div>
        )}
        <div ref={bottomRef} className="h-1" />
      </div>

      {/* Controls */}
      <div className="flex flex-col md:flex-row items-stretch md:items-center gap-4 relative z-10 font-sans mt-2">
        <button
          type="button"
          onClick={recording ? stopRecording : startRecording}
          disabled={loading}
          className={`flex-shrink-0 px-6 py-3.5 rounded-full text-xs tracking-[0.15em] uppercase font-medium transition-all duration-300 w-full md:w-auto shadow-lg flex items-center justify-center gap-2 ${
            recording
              ? "bg-red-900/40 text-red-400 border border-red-500/50 hover:bg-red-900/60 shadow-[0_0_15px_rgba(239,68,68,0.2)]"
              : loading
              ? "border border-gold/20 text-gold/40 cursor-not-allowed"
              : "surface text-gold border-gold/40 hover:bg-gold hover:text-charcoal-deep hover:border-gold hover:shadow-[0_0_20px_rgba(201,169,110,0.3)] group"
          }`}
        >
          {recording ? (
            <>
              <span className="w-2 h-2 rounded-full bg-red-500 animate-[pulse_1s_ease-in-out_infinite]" />
              Stop Recording
            </>
          ) : (
            <>
              <span className="text-[14px] group-hover:text-charcoal-deep transition-colors">🎤</span>
              Hold to Speak
            </>
          )}
        </button>
        
        <form onSubmit={handleSubmit} className="flex-1 flex gap-3 w-full">
          <div className="relative flex-1">
            <input
              className="w-full bg-charcoal-deep/80 border border-gold/30 focus:border-gold focus:ring-1 focus:ring-gold/50 rounded-full pl-5 pr-4 py-3.5 text-sm text-warm-white placeholder:text-muted/60 outline-none transition-all shadow-inner"
              placeholder="Or type your request here…"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              disabled={loading}
            />
          </div>
          <button
            type="submit"
            disabled={loading || !input.trim()}
            className="px-8 py-3.5 rounded-full bg-gradient-to-r from-gold to-gold-dark text-charcoal-deep font-semibold text-xs tracking-[0.15em] uppercase disabled:opacity-50 disabled:cursor-not-allowed hover:shadow-[0_0_20px_rgba(201,169,110,0.4)] transition-all flex-shrink-0"
          >
            Send
          </button>
        </form>
      </div>

      <style>{`
        @keyframes fadeIn {
          0% { opacity: 0; transform: translateY(5px); }
          100% { opacity: 1; transform: translateY(0); }
        }
        .custom-scrollbar::-webkit-scrollbar {
          width: 5px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: rgba(10, 10, 10, 0.4);
          border-radius: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: rgba(201, 169, 110, 0.3);
          border-radius: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: rgba(201, 169, 110, 0.6);
        }
      `}</style>
    </div>
  );
}
